import{_ as p,C as t,o as h,c as l,j as n,a as d,E as a,a4 as s}from"./chunks/framework.DeS7hvj6.js";const y=JSON.parse('{"title":"How Fuzzy Search Works","description":"An interactive visual explanation of edit distance and the Bitap algorithm — how Fuse.js finds approximate string matches with typo tolerance.","frontmatter":{"title":"How Fuzzy Search Works","description":"An interactive visual explanation of edit distance and the Bitap algorithm — how Fuse.js finds approximate string matches with typo tolerance.","sidebarDepth":0,"head":[["link",{"rel":"canonical","href":"https://www.fusejs.io/articles/how-fuzzy-search-works.html"}],["script",{"type":"application/ld+json"},"{\\n  \\"@context\\": \\"https://schema.org\\",\\n  \\"@type\\": \\"Article\\",\\n  \\"headline\\": \\"How Fuzzy Search Works\\",\\n  \\"description\\": \\"An interactive visual explanation of edit distance and the Bitap algorithm — how Fuse.js finds approximate string matches with typo tolerance.\\",\\n  \\"url\\": \\"https://www.fusejs.io/articles/how-fuzzy-search-works.html\\",\\n  \\"datePublished\\": \\"2026-04-09\\",\\n  \\"author\\": {\\n    \\"@type\\": \\"Person\\",\\n    \\"name\\": \\"Kiro Risk\\"\\n  },\\n  \\"publisher\\": {\\n    \\"@type\\": \\"Organization\\",\\n    \\"name\\": \\"Fuse.js\\",\\n    \\"url\\": \\"https://www.fusejs.io\\"\\n  }\\n}\\n"]]},"headers":[],"relativePath":"articles/how-fuzzy-search-works.md","filePath":"articles/how-fuzzy-search-works.md"}'),u={name:"articles/how-fuzzy-search-works.md"};function m(g,e,f,w,b,k){const o=t("PublishDate"),i=t("FuzzyMatchDemo"),r=t("ThresholdDemo"),c=t("BitapDemo");return h(),l("div",null,[e[0]||(e[0]=n("h1",{id:"how-fuzzy-search-works",tabindex:"-1"},[d("How Fuzzy Search Works "),n("a",{class:"header-anchor",href:"#how-fuzzy-search-works","aria-label":'Permalink to "How Fuzzy Search Works"'},"​")],-1)),a(o,{date:"2026-04-09"}),e[1]||(e[1]=s('<p>When you search for &quot;javscript&quot; and Fuse.js returns &quot;JavaScript&quot;, it&#39;s using <strong>approximate string matching</strong> — finding strings that are <em>close</em> to your query even when they don&#39;t match exactly.</p><p>The core idea is <strong>edit distance</strong>: the minimum number of single-character operations (insertions, deletions, substitutions) needed to transform one string into another.</p><p>For example, turning &quot;javscript&quot; into &quot;javascript&quot; requires:</p><ul><li><strong>Substitute</strong> <code>o</code> → <code>a</code> (at position 2)</li><li><strong>Insert</strong> <code>a</code> (at position 4)</li><li><strong>Insert</strong> <code>s</code> (at position 10)</li></ul><p>That&#39;s an edit distance of 3. The lower the distance relative to the string length, the better the match.</p><h2 id="edit-distance-demo" tabindex="-1">Edit Distance Demo <a class="header-anchor" href="#edit-distance-demo" aria-label="Permalink to &quot;Edit Distance Demo&quot;">​</a></h2><p>Step through the alignment between any two strings to see how edit distance is computed.</p>',7)),a(i),e[2]||(e[2]=s('<h2 id="from-edit-distance-to-fuzziness-score" tabindex="-1">From Edit Distance to Fuzziness Score <a class="header-anchor" href="#from-edit-distance-to-fuzziness-score" aria-label="Permalink to &quot;From Edit Distance to Fuzziness Score&quot;">​</a></h2><p>Fuse.js converts edit distance into a <strong>fuzziness score</strong> between 0 and 1:</p><ul><li><code>0</code> — perfect match (edit distance of 0)</li><li><code>1</code> — complete mismatch</li></ul><p>This score is then combined with other factors like key weight and field-length normalization to produce the final relevance ranking.</p><p>The <code>threshold</code> option (default <code>0.6</code>) controls the cutoff — results with a score above the threshold are excluded. Drag the slider to see how it affects which results make the cut:</p>',5)),a(r),e[3]||(e[3]=s(`<p>See <a href="/fuzzy-search.html">Fuzzy Search</a> for details on configuring threshold, distance, location, and scoring.</p><h2 id="under-the-hood-bitap" tabindex="-1">Under the Hood: Bitap <a class="header-anchor" href="#under-the-hood-bitap" aria-label="Permalink to &quot;Under the Hood: Bitap&quot;">​</a></h2><p>Fuse.js doesn&#39;t use a traditional dynamic programming table to compute edit distance. Instead, it uses the <a href="https://en.wikipedia.org/wiki/Bitap_algorithm" target="_blank" rel="noreferrer">Bitap algorithm</a>, which encodes the pattern as bitmasks and uses bitwise operations to check all character positions in parallel. This makes it fast — especially for short patterns.</p><div class="tip custom-block"><p class="custom-block-title">Why 32 characters?</p><p>The algorithm encodes the pattern as a bitmask and uses bitwise operators (<code>&lt;&lt;</code>, <code>|</code>, <code>&amp;</code>) to process all positions in a single CPU operation. JavaScript&#39;s bitwise operators work on 32-bit integers — that&#39;s the limit. Longer patterns are split into 32-character chunks and searched independently.</p></div><p>Here&#39;s how it works for <strong>exact matching</strong> (zero errors):</p><ol><li><p><strong>Build bitmasks</strong> — for each character in the pattern, create a bitmask where bit <code>i</code> is <code>1</code> if the character matches position <code>i</code>, and <code>0</code> otherwise. Fuse.js does this via <code>createPatternAlphabet()</code>. For the pattern <code>test</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>         t  e  s  t</span></span>
<span class="line"><span>mask[t]  1  0  0  1</span></span>
<span class="line"><span>mask[e]  0  1  0  0</span></span>
<span class="line"><span>mask[s]  0  0  1  0</span></span></code></pre></div></li><li><p><strong>Initialize state</strong> — the state vector <code>R</code> starts as all <code>0</code>s (no matches yet).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>     t  e  s  t</span></span>
<span class="line"><span>R =  0  0  0  0</span></span></code></pre></div></li><li><p><strong>Scan the text</strong> — for each character, three things happen in a single bitwise operation:</p><ul><li><strong>Seed</strong> — a new potential match starts at the first pattern position</li><li><strong>Propagate</strong> — existing partial matches advance to the next position</li><li><strong>Kill</strong> — any position where the text character doesn&#39;t match the pattern is reset to <code>0</code></li></ul></li><li><p><strong>Match</strong> — when the bit for the last pattern position is <code>1</code>, the entire pattern has been matched.</p></li></ol><p>For example, searching for <code>test</code> in <code>&quot;xtest&quot;</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>                 t  e  s  t</span></span>
<span class="line"><span>Start:      R =  0  0  0  0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Read &#39;x&#39;:   R =  0  0  0  0   ← &#39;x&#39; isn&#39;t in the pattern, seed killed</span></span>
<span class="line"><span>Read &#39;t&#39;:   R =  1  0  0  0   ← &#39;t&#39; matches position 0, partial match starts</span></span>
<span class="line"><span>Read &#39;e&#39;:   R =  0  1  0  0   ← &#39;e&#39; matches position 1, match continues</span></span>
<span class="line"><span>Read &#39;s&#39;:   R =  0  0  1  0   ← &#39;s&#39; matches position 2, still going</span></span>
<span class="line"><span>Read &#39;t&#39;:   R =  1  0  0  1   ← &#39;t&#39; matches position 3 → full match!</span></span>
<span class="line"><span>                                  (also starts a new match at position 0)</span></span></code></pre></div><p>Step through it yourself:</p>`,9)),a(c),e[4]||(e[4]=s(`<h2 id="handling-typos-approximate-matching" tabindex="-1">Handling Typos: Approximate Matching <a class="header-anchor" href="#handling-typos-approximate-matching" aria-label="Permalink to &quot;Handling Typos: Approximate Matching&quot;">​</a></h2><p>The demo above only shows exact matching. But Fuse.js is a <em>fuzzy</em> search library — it needs to handle typos, missing characters, and extra characters. It does this by running the Bitap algorithm multiple times, allowing one more error each pass.</p><p>Instead of a single state vector <code>R</code>, Fuse maintains multiple: <code>R0</code> (zero errors), <code>R1</code> (one error), <code>R2</code> (two errors), and so on. When a partial match dies in one level because the characters don&#39;t match, it can continue in the next level — counting that mismatch as an error:</p><ul><li><strong>Substitution</strong> — a partial match in <code>R0</code> hits a wrong character. Instead of dying, it continues in <code>R1</code> with one error charged.</li><li><strong>Deletion</strong> — a partial match skips a pattern position (a character is missing from the text). It continues in <code>R1</code>.</li><li><strong>Insertion</strong> — a partial match skips a text character (an extra character in the text). It continues in <code>R1</code>.</li></ul><p>For example, searching for <code>test</code> in <code>&quot;tset&quot;</code> (a transposition):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>                   t  e  s  t</span></span>
<span class="line"><span>R0 (0 errors):     1  0  0  0   ← &#39;t&#39; matches, but &#39;s&#39; ≠ &#39;e&#39; — exact match dies</span></span>
<span class="line"><span>R1 (1 error):      1  1  0  0   ← the mismatch continues here as 1 error</span></span>
<span class="line"><span>R2 (2 errors):     1  1  1  1   ← another mismatch, 2 errors — still matches!</span></span></code></pre></div><p>The algorithm stops adding error levels when the score exceeds the <code>threshold</code>. This is how <code>threshold</code> controls fuzziness — a lower threshold means fewer error levels are tried, requiring closer matches.</p>`,7))])}const z=p(u,[["render",m]]);export{y as __pageData,z as default};
